/**
 * docx-template.js
 *
 * Reusable document generation module for Jason English's resume.
 * Generated by /init-docx-template from: Jason English Resume - Base.docx
 *
 * This file is committed to the repo. Re-run /init-docx-template only if the
 * .docx formatting template changes, then commit the regenerated module.
 */

const {
  Document, Packer, Paragraph, TextRun, Tab, AlignmentType,
  LevelFormat, TabStopType, TabStopPosition, BorderStyle, WidthType,
} = require('docx');
const fs = require('fs');
const path = require('path');

// ---------------------------------------------------------------------------
// PAGE + FONT CONSTANTS (extracted from Jason English Resume - Base.docx)
// ---------------------------------------------------------------------------

const FONT = 'Calibri';

// Page: US Letter, 0.75" margins all sides
const PAGE = {
  size: { width: 12240, height: 15840 },
  margin: { top: 1080, right: 1080, bottom: 1080, left: 1080 },
};

// Content width = 12240 - 1080 - 1080 = 10080 DXA
const CONTENT_WIDTH = 10080;

// Right-aligned tab for date column
const DATE_TAB = 9360;

// Font sizes in half-points
const SZ = {
  name:    48,  // 24pt
  contact: 18,  //  9pt
  section: 20,  // 10pt
  company: 28,  // 14pt
  role:    24,  // 12pt
  body:    18,  //  9pt
};

// ---------------------------------------------------------------------------
// NUMBERING CONFIG (formatted resume bullets)
// ---------------------------------------------------------------------------

const NUMBERING_CONFIG = [
  {
    reference: 'bullets',
    levels: [
      {
        level: 0,
        format: LevelFormat.BULLET,
        text: '\u25CF',  // ●
        alignment: AlignmentType.LEFT,
        style: {
          paragraph: {
            indent: { left: 360, hanging: 180 },
            spacing: { before: 20, after: 20, line: 240 },
          },
        },
      },
    ],
  },
  {
    reference: 'subbullets',
    levels: [
      {
        level: 0,
        format: LevelFormat.BULLET,
        text: '\u25AA',  // ▪
        alignment: AlignmentType.LEFT,
        style: {
          paragraph: {
            indent: { left: 630, hanging: 180 },
            spacing: { before: 20, after: 20, line: 240 },
          },
        },
      },
    ],
  },
];

// ---------------------------------------------------------------------------
// FORMATTED RESUME HELPERS
// ---------------------------------------------------------------------------

/** Name line (top of resume) */
function nameBlock(name) {
  return new Paragraph({
    spacing: { after: 0 },
    children: [new TextRun({ text: name, font: FONT, size: SZ.name, bold: false })],
  });
}

/** Professional title line */
function titleBlock(title) {
  return new Paragraph({
    spacing: { before: 40, after: 40 },
    children: [new TextRun({ text: title, font: FONT, size: SZ.section, bold: true })],
  });
}

/** Contact info line */
function contactBlock(contact) {
  return new Paragraph({
    spacing: { before: 0, after: 160 },
    children: [new TextRun({ text: contact, font: FONT, size: SZ.contact })],
  });
}

/** Section header (e.g. "Summary", "Skills", "Experience") */
function sectionHeader(label) {
  return new Paragraph({
    spacing: { before: 160, after: 60 },
    border: {
      bottom: { style: BorderStyle.SINGLE, size: 6, color: '000000', space: 1 },
    },
    children: [new TextRun({ text: label.toUpperCase(), font: FONT, size: SZ.section, bold: true })],
  });
}

/**
 * Company / employer line.
 * Format: Company | Location [TAB] Date — all bold; date is 11pt.
 */
function companyLine(company, location, dateRange) {
  const children = [
    new TextRun({ text: company, font: FONT, size: SZ.company, bold: true }),
  ];
  if (location) {
    children.push(new TextRun({ text: ' | ' + location, font: FONT, size: SZ.body, bold: true }));
  }
  if (dateRange) {
    children.push(new TextRun({ children: [new Tab()], font: FONT }));
    children.push(new TextRun({ text: dateRange, font: FONT, size: 22, bold: true }));
  }
  return new Paragraph({
    tabStops: [{ type: TabStopType.RIGHT, position: DATE_TAB }],
    spacing: { before: 200, after: 20 },
    children,
  });
}

/**
 * Role / job title line.
 * Title is bold and underlined. Optional date appears inline in parens — not bold, not underlined.
 * @param {string} role
 * @param {string} [dateRange]  e.g. "Feb 2024 – Feb 2026"
 * @param {boolean} [bold=true]
 */
function roleLine(role, dateRange, bold = true) {
  const children = [
    new TextRun({ text: role, font: FONT, size: SZ.role, bold, underline: {} }),
  ];
  if (dateRange) {
    children.push(new TextRun({ text: ' (' + dateRange + ')', font: FONT, size: SZ.section, bold: false }));
  }
  return new Paragraph({
    spacing: { before: 100, after: 20 },
    children,
  });
}

/** Italic note line (e.g. customer highlights, assigned accounts) */
function italicNote(text) {
  return new Paragraph({
    spacing: { before: 0, after: 20 },
    children: [new TextRun({ text, font: FONT, size: SZ.body, italics: true })],
  });
}

/** Top-level bullet — accepts plain string or TextRun array (for inline bold) */
function bullet(textOrRuns, { bold = false } = {}) {
  const children = Array.isArray(textOrRuns)
    ? textOrRuns
    : [new TextRun({ text: textOrRuns, font: FONT, size: SZ.body, bold })];
  return new Paragraph({
    numbering: { reference: 'bullets', level: 0 },
    children,
  });
}

/** Sub-bullet (one level in) */
function subBullet(text) {
  return new Paragraph({
    numbering: { reference: 'subbullets', level: 0 },
    children: [new TextRun({ text, font: FONT, size: SZ.body })],
  });
}

/** Plain (non-bulleted) body paragraph */
function plainLine(text, { bold = false, italic = false, spacing = {} } = {}) {
  return new Paragraph({
    spacing: { before: 20, after: 20, ...spacing },
    children: [new TextRun({ text, font: FONT, size: SZ.body, bold, italics: italic })],
  });
}

/** Summary paragraph */
function summaryBlock(text) {
  return new Paragraph({
    spacing: { before: 40, after: 40 },
    children: [new TextRun({ text, font: FONT, size: SZ.body })],
  });
}

/** Education line: "Institution | Degree (Year)" */
function educationBlock(institution, degree, year) {
  return new Paragraph({
    spacing: { before: 40, after: 20 },
    children: [
      new TextRun({ text: institution, font: FONT, size: SZ.body, bold: true }),
      new TextRun({ text: ' | ' + degree + (year ? ' (' + year + ')' : ''), font: FONT, size: SZ.body }),
    ],
  });
}

// ---------------------------------------------------------------------------
// WORKDAY ATS HELPERS
// ---------------------------------------------------------------------------

const W_FONT = 'Calibri';
const W_SZ = 22;  // 11pt in half-points

function wSection(label) {
  return new Paragraph({
    spacing: { before: 240, after: 60 },
    children: [new TextRun({ text: label.toUpperCase(), font: W_FONT, size: W_SZ, bold: true })],
  });
}

function wHeader(text) {
  return new Paragraph({
    spacing: { before: 160, after: 0 },
    children: [new TextRun({ text, font: W_FONT, size: W_SZ, bold: true })],
  });
}

function wRole(title, dateRange) {
  return new Paragraph({
    spacing: { before: 80, after: 0 },
    children: [
      new TextRun({ text: title + '  |  ' + dateRange, font: W_FONT, size: W_SZ }),
    ],
  });
}

function wNote(text) {
  return new Paragraph({
    spacing: { before: 0, after: 0 },
    children: [new TextRun({ text, font: W_FONT, size: W_SZ, italics: true })],
  });
}

/** Workday bullet — accepts plain string or TextRun array (for inline bold) */
function wBullet(textOrRuns) {
  const children = Array.isArray(textOrRuns)
    ? [new TextRun({ text: '- ', font: W_FONT, size: W_SZ }), ...textOrRuns]
    : [new TextRun({ text: '- ' + textOrRuns, font: W_FONT, size: W_SZ })];
  return new Paragraph({
    spacing: { before: 0, after: 0 },
    children,
  });
}

function wPlain(text, { bold = false } = {}) {
  return new Paragraph({
    spacing: { before: 40, after: 40 },
    children: [new TextRun({ text, font: W_FONT, size: W_SZ, bold })],
  });
}

// ---------------------------------------------------------------------------
// DOCUMENT GENERATOR
// ---------------------------------------------------------------------------

/**
 * Build and write both formatted and Workday .docx files.
 *
 * @param {Paragraph[]} formattedChildren  - Array of Paragraph objects for the styled version
 * @param {Paragraph[]} workdayChildren    - Array of Paragraph objects for the Workday/ATS version
 * @param {string} outputBase              - Base path without extension, e.g. "resumes/acme-senior-pm-2026-03-09"
 * @param {object} [opts]
 * @param {boolean} [opts.formatted=true]  - Write formatted .docx
 * @param {boolean} [opts.workday=true]    - Write Workday .docx
 * @returns {Promise<{formatted: string|null, workday: string|null}>}
 */
async function generateDocs(formattedChildren, workdayChildren, outputBase, opts = {}) {
  const { formatted: doFormatted = true, workday: doWorkday = true } = opts;
  const results = { formatted: null, workday: null };

  if (doFormatted) {
    const doc = new Document({
      numbering: { config: NUMBERING_CONFIG },
      styles: {
        default: {
          document: { run: { font: FONT, size: SZ.body } },
        },
      },
      sections: [{
        properties: {
          page: {
            size: PAGE.size,
            margin: PAGE.margin,
          },
        },
        children: formattedChildren,
      }],
    });
    const buffer = await Packer.toBuffer(doc);
    const outPath = outputBase + '.docx';
    fs.writeFileSync(outPath, buffer);
    results.formatted = outPath;
  }

  if (doWorkday) {
    const doc = new Document({
      styles: {
        default: {
          document: { run: { font: W_FONT, size: W_SZ } },
        },
      },
      sections: [{
        properties: {
          page: {
            size: PAGE.size,
            margin: { top: 1440, right: 1440, bottom: 1440, left: 1440 },
          },
        },
        children: workdayChildren,
      }],
    });
    const buffer = await Packer.toBuffer(doc);
    const outPath = outputBase + '-workday.docx';
    fs.writeFileSync(outPath, buffer);
    results.workday = outPath;
  }

  return results;
}

// ---------------------------------------------------------------------------
// EXPORTS
// ---------------------------------------------------------------------------

module.exports = {
  // Constants (for custom generation scripts)
  FONT, W_FONT, PAGE, CONTENT_WIDTH, DATE_TAB, SZ, W_SZ, NUMBERING_CONFIG,

  // Formatted resume helpers
  nameBlock,
  titleBlock,
  contactBlock,
  sectionHeader,
  companyLine,
  roleLine,
  italicNote,
  bullet,
  subBullet,
  plainLine,
  summaryBlock,
  educationBlock,

  // Workday ATS helpers
  wSection,
  wHeader,
  wRole,
  wNote,
  wBullet,
  wPlain,

  // Generator
  generateDocs,
};
